0.15558457,-0.02198644,-0.03052548,0.05316124,-0.02389063,0.06066947,0.00901152,0.00032868,-0.00977014,-0.03462387,0.06385630,-0.06475075,0.01671519,-0.00031465,-0.01475039,0.00718280,0.01480036,-0.01834841,-0.06209723,-0.03394740,-0.07239220,-0.02395391,0.00518280,-0.02207304,-0.04365921,0.04632608,-0.04155401,-0.01918281,0.00942419,-0.00502755,-0.00159205,0.00212374,0.03821166,0.06546175,0.03924524,0.01599245,-0.02611043,-0.00392792,0.05652845,-0.02206330,0.05776290,0.01437085,0.01559624]',E'Multiple files\n\nSee the detailed [example code](https://github.com/gin-gonic/examples/tree/master/upload-file/multiple).\n\n```go\nfunc main() {\n  router := gin.Default()\n  // Set a lower memory limit for multipart forms (default is 32 MiB)\n  router.MaxMultipartMemory = 8 << 20  // 8 MiB\n  router.POST("/upload", func(c *gin.Context) {\n    // Multipart form\n    form, _ := c.MultipartForm()\n    files := form.File["upload[]"]\n\n    for _, file := range files {\n      log.Println(file.Filename)\n\n      // Upload the file to specific dst.\n      c.SaveUploadedFile(file, dst)\n    }\n    c.String(http.StatusOK, fmt.Sprintf("%d files uploaded!", len(files)))\n  })\n  router.Run(":8080")\n}\n```\n\nHow to `curl`:\n\n```bash\ncurl -X POST http://localhost:8080/upload \\\n  -F "upload[]=@/Users/appleboy/test1.zip" \\\n  -F "upload[]=@/Users/appleboy/test2.zip" \\\n  -H "Content-Type: multipart/form-data"\n```','{"source": "go-gin", "version": "1.12", "language": "go", "title": "Gin Quick Start", "section_title": "doc", "url": "https://github.com/gin-gonic/gin/blob/master/docs/doc.md", "topics": "gin,http,doc", "categories": "web,go,rest"}');
