2558,-0.00550264,0.06025953,0.06178103,-0.00122234,0.00802832,0.07852035,0.02618368,0.04356813,-0.02725965,0.10606555,-0.01292151,0.05854893,-0.08247439,0.01148340,-0.05336238,-0.02835997,-0.03947733,-0.01886239,0.05581892,0.01177071,-0.02220044,0.03983436,-0.00136450,-0.06104715,-0.05536826,-0.01985412,0.02471033,0.00895506,-0.05016294,-0.02633991,-0.01051516,0.02489471,0.03639899,0.06456489,-0.03070683,-0.05178995,0.00935800,-0.00702698,0.00265027,0.11942323,-0.04344006,-0.01327024]',E'Custom Middleware\n\n```go\nfunc Logger() gin.HandlerFunc {\n  return func(c *gin.Context) {\n    t := time.Now()\n\n    // Set example variable\n    c.Set("example", "12345")\n\n    // before request\n\n    c.Next()\n\n    // after request\n    latency := time.Since(t)\n    log.Print(latency)\n\n    // access the status we are sending\n    status := c.Writer.Status()\n    log.Println(status)\n  }\n}\n\nfunc main() {\n  r := gin.New()\n  r.Use(Logger())\n\n  r.GET("/test", func(c *gin.Context) {\n    example := c.MustGet("example").(string)\n\n    // it would print: "12345"\n    log.Println(example)\n  })\n\n  // Listen and serve on 0.0.0.0:8080\n  r.Run(":8080")\n}\n```','{"source": "go-gin", "version": "1.12", "language": "go", "title": "Gin Quick Start", "section_title": "doc", "url": "https://github.com/gin-gonic/gin/blob/master/docs/doc.md", "topics": "gin,http,doc", "categories": "web,go,rest"}');
