570680,0.02786333,0.00338560,0.02021579,0.01364887,-0.00033305,0.00815025,0.01600619,0.02289148,-0.06562550,0.07690750,-0.00303726,0.11551375,-0.07112132,-0.01025237,0.01368748,-0.00871418,-0.05548912,-0.05161659,0.02569208,0.00041562,-0.02544658,0.05695745,-0.01762894,-0.04922079,-0.05073073,-0.00173407,0.06598796,0.00797155,-0.02859314,-0.02196540,-0.02783465,0.02533929,0.03407893,0.05356968,-0.00018015,-0.00564089,0.04820796,-0.01736093,0.03816275,0.10660619,-0.02922725,-0.05156577]',E'Custom Recovery behavior\n\n```go\nfunc main() {\n  // Creates a router without any middleware by default\n  r := gin.New()\n\n  // Global middleware\n  // Logger middleware will write the logs to gin.DefaultWriter even if you set with GIN_MODE=release.\n  // By default gin.DefaultWriter = os.Stdout\n  r.Use(gin.Logger())\n\n  // Recovery middleware recovers from any panics and writes a 500 if there was one.\n  r.Use(gin.CustomRecovery(func(c *gin.Context, recovered any) {\n    if err, ok := recovered.(string); ok {\n      c.String(http.StatusInternalServerError, fmt.Sprintf("error: %s", err))\n    }\n    c.AbortWithStatus(http.StatusInternalServerError)\n  }))\n\n  r.GET("/panic", func(c *gin.Context) {\n    // panic with a string -- the custom middleware could save this to a database or report it to the user\n    panic("foo")\n  })\n\n  r.GET("/", func(c *gin.Context) {\n    c.String(http.StatusOK, "ohai")\n  })\n\n  // Listen and serve on 0.0.0.0:8080\n  r.Run(":8080")\n}\n```','{"source": "go-gin", "version": "1.12", "language": "go", "title": "Gin Quick Start", "section_title": "doc", "url": "https://github.com/gin-gonic/gin/blob/master/docs/doc.md", "topics": "gin,http,doc", "categories": "web,go,rest"}');
