9,0.12801090,0.01792596,0.00201660,0.01132598,0.02128760,0.04215434,0.04278036,0.03527513,0.05668864,-0.07926398,0.07402684,0.01400889,0.06631390,-0.03900045,0.01460562,-0.01057106,0.00993311,-0.08796385,-0.05627369,0.03660798,0.01208960,-0.02592207,0.00830069,0.01014312,-0.05530375,-0.00350133,-0.03715521,-0.02593319,-0.03921596,0.01600674,-0.03105774,0.00588924,-0.01430771,0.03003061,0.03046489,-0.05752190,-0.01533945,-0.00841613,0.01916576,0.00782898,0.09269489,-0.02484241,-0.01422999]',E'How to write log file\n\n```go\nfunc main() {\n  // Disable Console Color, you don''t need console color when writing the logs to file.\n  gin.DisableConsoleColor()\n\n  // Logging to a file.\n  f, _ := os.Create("gin.log")\n  gin.DefaultWriter = io.MultiWriter(f)\n\n  // Use the following code if you need to write the logs to file and console at the same time.\n  // gin.DefaultWriter = io.MultiWriter(f, os.Stdout)\n\n  router := gin.Default()\n  router.GET("/ping", func(c *gin.Context) {\n      c.String(http.StatusOK, "pong")\n  })\n\n   router.Run(":8080")\n}\n```','{"source": "go-gin", "version": "1.12", "language": "go", "title": "Gin Quick Start", "section_title": "doc", "url": "https://github.com/gin-gonic/gin/blob/master/docs/doc.md", "topics": "gin,http,doc", "categories": "web,go,rest"}');
