6987111,0.04081459,0.00627447,0.03773233,-0.00503356,0.02905379,0.09020717,0.00509710,0.03871279,-0.08189765,0.12847106,0.03378797,0.09614448,-0.05646231,0.00687729,-0.05599360,-0.04758259,-0.06955669,-0.02961708,0.01644726,0.02118495,-0.00304939,0.03386896,-0.03431650,-0.06897756,-0.01168105,0.02150674,0.02359021,-0.00883494,-0.01898498,-0.05074392,0.01113533,0.02256839,0.05367991,0.07880680,-0.01307623,-0.02899207,0.04390807,-0.00470981,0.00153537,0.05695989,-0.01485864,0.00183826]',E'Custom Log Format\n\n```go\nfunc main() {\n  router := gin.New()\n\n  // LoggerWithFormatter middleware will write the logs to gin.DefaultWriter\n  // By default gin.DefaultWriter = os.Stdout\n  router.Use(gin.LoggerWithFormatter(func(param gin.LogFormatterParams) string {\n\n    // your custom format\n    return fmt.Sprintf("%s - [%s] \\"%s %s %s %d %s \\"%s\\" %s\\"\\n",\n        param.ClientIP,\n        param.TimeStamp.Format(time.RFC1123),\n        param.Method,\n        param.Path,\n        param.Request.Proto,\n        param.StatusCode,\n        param.Latency,\n        param.Request.UserAgent(),\n        param.ErrorMessage,\n    )\n  }))\n  router.Use(gin.Recovery())\n\n  router.GET("/ping", func(c *gin.Context) {\n    c.String(http.StatusOK, "pong")\n  })\n\n  router.Run(":8080")\n}\n```\n\nSample Output\n\n```sh\n::1 - [Fri, 07 Dec 2018 17:04:38 JST] "GET /ping HTTP/1.1 200 122.767µs "Mozilla/5.0 (Macintosh; Intel Mac OS X 10_11_6) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/71.0.3578.80 Safari/537.36" "\n```','{"source": "go-gin", "version": "1.12", "language": "go", "title": "Gin Quick Start", "section_title": "doc", "url": "https://github.com/gin-gonic/gin/blob/master/docs/doc.md", "topics": "gin,http,doc", "categories": "web,go,rest"}');
