6,0.00629107,0.02578406,0.04905816,-0.02792132,-0.02948483,0.05521506,-0.00392860,0.01129927,-0.05699309,0.11400130,-0.03587374,0.10291526,-0.06991937,0.04591221,0.00118265,0.00763490,-0.08197603,-0.04560502,0.04102174,-0.01754927,0.03650119,0.04068137,-0.03912872,-0.03243110,-0.01403645,-0.01735004,0.04896818,0.03009466,-0.02404506,-0.00561601,0.01145314,-0.00413713,0.04470184,0.02951672,-0.01469390,-0.07386364,0.00567712,-0.02447624,-0.01855159,0.08476900,-0.03984043,-0.00615927]',E'Skip logging\n\n```go\nfunc main() {\n  router := gin.New()\n\n  // skip logging for desired paths by setting SkipPaths in LoggerConfig\n  loggerConfig := gin.LoggerConfig{SkipPaths: []string{"/metrics"}}\n\n  // skip logging based on your logic by setting Skip func in LoggerConfig\n  loggerConfig.Skip = func(c *gin.Context) bool {\n      // as an example skip non server side errors\n      return c.Writer.Status() < http.StatusInternalServerError\n  }\n\n  router.Use(gin.LoggerWithConfig(loggerConfig))\n  router.Use(gin.Recovery())\n\n  // skipped\n  router.GET("/metrics", func(c *gin.Context) {\n      c.Status(http.StatusNotImplemented)\n  })\n\n  // skipped\n  router.GET("/ping", func(c *gin.Context) {\n      c.String(http.StatusOK, "pong")\n  })\n\n  // not skipped\n  router.GET("/data", func(c *gin.Context) {\n    c.Status(http.StatusNotImplemented)\n  })\n\n  router.Run(":8080")\n}\n\n```','{"source": "go-gin", "version": "1.12", "language": "go", "title": "Gin Quick Start", "section_title": "doc", "url": "https://github.com/gin-gonic/gin/blob/master/docs/doc.md", "topics": "gin,http,doc", "categories": "web,go,rest"}');
