9161065,0.00907401,0.02971860,0.03927945,0.02100589,-0.01272185,-0.01592936,0.02728544,0.01612772,-0.03358448,0.14194714,-0.02725508,0.01581995,-0.04430160,-0.03234660,0.00241976,-0.04818718,-0.03937138,-0.04943299,0.03677800,-0.03874261,0.04171140,0.04715723,0.00497667,-0.05049135,0.03582738,-0.02423400,-0.02520645,0.01421785,0.00629352,-0.06421174,-0.01363786,0.03480436,0.00699426,0.03773148,-0.05109492,-0.01715256,0.05418218,-0.04908282,0.00362878,0.03565254,-0.00764122,0.01615575]',E'Only Bind Query String\n\n`ShouldBindQuery` function only binds the query params and not the post data. See the [detail information](https://github.com/gin-gonic/gin/issues/742#issuecomment-315953017).\n\n```go\npackage main\n\nimport (\n  "log"\n  "net/http"\n\n  "github.com/gin-gonic/gin"\n)\n\ntype Person struct {\n  Name    string `form:"name"`\n  Address string `form:"address"`\n}\n\nfunc main() {\n  route := gin.Default()\n  route.Any("/testing", startPage)\n  route.Run(":8085")\n}\n\nfunc startPage(c *gin.Context) {\n  var person Person\n  if c.ShouldBindQuery(&person) == nil {\n    log.Println("====== Only Bind By Query String ======")\n    log.Println(person.Name)\n    log.Println(person.Address)\n  }\n  c.String(http.StatusOK, "Success")\n}\n\n```','{"source": "go-gin", "version": "1.12", "language": "go", "title": "Gin Quick Start", "section_title": "doc", "url": "https://github.com/gin-gonic/gin/blob/master/docs/doc.md", "topics": "gin,http,doc", "categories": "web,go,rest"}');
