9833896,-0.00574545,-0.00252241,0.00309627,-0.00171452,0.01102899,0.07271525,0.01386828,-0.01419171,-0.01335730,0.11441174,-0.02716350,0.00149397,0.02103526,-0.01884693,-0.06390280,0.00622847,-0.03163471,0.00522170,0.01308029,-0.02446716,0.05330101,-0.01165979,-0.01188828,-0.00634738,0.00619113,-0.01617379,0.00923110,0.01981136,-0.02209271,-0.03937973,-0.02567100,0.00294289,0.01993575,0.01320264,-0.01961164,-0.03643246,0.00177876,-0.03309698,-0.01887019,0.04357770,0.03792526,0.01889079]',E'Bind Header\n\n```go\npackage main\n\nimport (\n  "fmt"\n  "net/http"\n\n  "github.com/gin-gonic/gin"\n)\n\ntype testHeader struct {\n  Rate   int    `header:"Rate"`\n  Domain string `header:"Domain"`\n}\n\nfunc main() {\n  r := gin.Default()\n  r.GET("/", func(c *gin.Context) {\n    h := testHeader{}\n\n    if err := c.ShouldBindHeader(&h); err != nil {\n      c.JSON(http.StatusOK, err)\n    }\n\n    fmt.Printf("%#v\\n", h)\n    c.JSON(http.StatusOK, gin.H{"Rate": h.Rate, "Domain": h.Domain})\n  })\n\n  r.Run()\n\n// client\n// curl -H "rate:300" -H "domain:music" 127.0.0.1:8080/\n// output\n// {"Domain":"music","Rate":300}\n}\n```','{"source": "go-gin", "version": "1.12", "language": "go", "title": "Gin Quick Start", "section_title": "doc", "url": "https://github.com/gin-gonic/gin/blob/master/docs/doc.md", "topics": "gin,http,doc", "categories": "web,go,rest"}');
