,0.19511698,-0.00945975,0.02351259,0.04325126,0.03582914,-0.01480990,0.04479267,0.01152762,0.03078259,-0.02166880,0.14752550,-0.00762549,-0.00503961,-0.06790391,-0.02691906,-0.00620096,-0.02194134,-0.06173848,-0.02747292,0.02595610,-0.05773484,-0.00627759,0.01330338,-0.04301518,-0.05542966,0.02479119,0.00683708,-0.01289249,0.02458274,0.01420961,-0.05238419,-0.02572609,-0.01471332,0.03045606,0.01135366,-0.05797209,0.01404937,-0.00555546,-0.03238636,0.00085130,0.00659147,-0.00559754,0.03505458]',E'Bind HTML checkboxes\n\nSee the [detail information](https://github.com/gin-gonic/gin/issues/129#issuecomment-124260092)\n\nmain.go\n\n```go\n...\n\ntype myForm struct {\n    Colors []string `form:"colors[]"`\n}\n\n...\n\nfunc formHandler(c *gin.Context) {\n    var fakeForm myForm\n    c.ShouldBind(&fakeForm)\n    c.JSON(http.StatusOK, gin.H{"color": fakeForm.Colors})\n}\n\n...\n\n```\n\nform.html\n\n```html\n<form action="/" method="POST">\n  <p>Check some colors</p>\n  <label for="red">Red</label>\n  <input type="checkbox" name="colors[]" value="red" id="red" />\n  <label for="green">Green</label>\n  <input type="checkbox" name="colors[]" value="green" id="green" />\n  <label for="blue">Blue</label>\n  <input type="checkbox" name="colors[]" value="blue" id="blue" />\n  <input type="submit" />\n</form>\n```\n\nresult:\n\n```json\n{ "color": ["red", "green", "blue"] }\n```','{"source": "go-gin", "version": "1.12", "language": "go", "title": "Gin Quick Start", "section_title": "doc", "url": "https://github.com/gin-gonic/gin/blob/master/docs/doc.md", "topics": "gin,http,doc", "categories": "web,go,rest"}');
