07251,0.01917052,0.02048583,0.08487082,-0.01008441,-0.00842536,0.09671422,0.04580152,-0.01249321,0.00646475,-0.00058184,-0.03665251,0.04566324,-0.02453238,-0.02465075,-0.04448706,-0.03929790,-0.04567834,-0.03127401,-0.00960092,-0.03749845,-0.01542432,0.02320781,-0.03569783,-0.00744314,-0.02327855,0.01406301,0.01575409,0.00944446,-0.01916650,-0.02111857,-0.02983167,-0.00018606,0.07241868,0.03482527,0.02225168,-0.01364306,0.00913930,0.03254022,-0.04214618,0.06635769,-0.01706986,0.02598128]',E'Support Let''s Encrypt\n\nexample for 1-line LetsEncrypt HTTPS servers.\n\n```go\npackage main\n\nimport (\n  "log"\n  "net/http"\n\n  "github.com/gin-gonic/autotls"\n  "github.com/gin-gonic/gin"\n)\n\nfunc main() {\n  r := gin.Default()\n\n  // Ping handler\n  r.GET("/ping", func(c *gin.Context) {\n    c.String(http.StatusOK, "pong")\n  })\n\n  log.Fatal(autotls.Run(r, "example1.com", "example2.com"))\n}\n```\n\nexample for custom autocert manager.\n\n```go\npackage main\n\nimport (\n  "log"\n  "net/http"\n\n  "github.com/gin-gonic/autotls"\n  "github.com/gin-gonic/gin"\n  "golang.org/x/crypto/acme/autocert"\n)\n\nfunc main() {\n  r := gin.Default()\n\n  // Ping handler\n  r.GET("/ping", func(c *gin.Context) {\n    c.String(http.StatusOK, "pong")\n  })\n\n  m := autocert.Manager{\n    Prompt:     autocert.AcceptTOS,\n    HostPolicy: autocert.HostWhitelist("example1.com", "example2.com"),\n    Cache:      autocert.DirCache("/var/www/.cache"),\n  }\n\n  log.Fatal(autotls.RunWithManager(r, &m))\n}\n```','{"source": "go-gin", "version": "1.12", "language": "go", "title": "Gin Quick Start", "section_title": "doc", "url": "https://github.com/gin-gonic/gin/blob/master/docs/doc.md", "topics": "gin,http,doc", "categories": "web,go,rest"}');
