9177,0.04482057,0.05447104,0.01063988,0.01411918,-0.01863866,0.05209960,0.02128631,-0.01312913,0.04583786,-0.04856000,0.06137760,-0.03526009,-0.02829310,-0.03601596,0.01806878,-0.01467957,-0.06906567,0.03893076,-0.06435657,-0.02718340,0.04636211,-0.03682819,-0.08107203,-0.03849821,-0.05185886,0.00300698,0.01139158,-0.05033726,-0.03665357,-0.00035397,-0.01845047,0.08233561,-0.00237149,0.01603755,-0.00622336,-0.01921832,0.00371694,-0.04246350,0.04106208,-0.03580935,-0.01674116]',E'Run multiple service using Gin\n\nSee the [question](https://github.com/gin-gonic/gin/issues/346) and try the following example:\n\n```go\npackage main\n\nimport (\n  "log"\n  "net/http"\n  "time"\n\n  "github.com/gin-gonic/gin"\n  "golang.org/x/sync/errgroup"\n)\n\nvar (\n  g errgroup.Group\n)\n\nfunc router01() http.Handler {\n  e := gin.New()\n  e.Use(gin.Recovery())\n  e.GET("/", func(c *gin.Context) {\n    c.JSON(\n      http.StatusOK,\n      gin.H{\n        "code":  http.StatusOK,\n        "error": "Welcome server 01",\n      },\n    )\n  })','{"source": "go-gin", "version": "1.12", "language": "go", "title": "Gin Quick Start", "section_title": "doc", "url": "https://github.com/gin-gonic/gin/blob/master/docs/doc.md", "topics": "gin,http,doc", "categories": "web,go,rest"}');
