6145,0.00764603,0.00914595,-0.01866542,0.00454120,0.08399197,0.03316732,0.00769136,0.00583734,0.05474796,-0.04102941,0.01081315,-0.03598499,0.00894663,-0.06502473,-0.03276518,-0.08532386,-0.02725396,0.02502253,-0.06228005,-0.00691761,0.04299118,-0.07333957,-0.04061608,-0.03039933,-0.04219807,-0.01174385,-0.00276944,-0.03115385,-0.05573839,0.02792527,-0.01829119,0.06270877,0.00484396,0.00867703,-0.03450112,0.00499714,-0.01958300,-0.00621172,0.07513210,0.01590684,0.04756640]',E'http2 server push\n\nhttp.Pusher is supported only **go1.8+**. See the [golang blog](https://go.dev/blog/h2push) for detail information.\n\n```go\npackage main\n\nimport (\n  "html/template"\n  "log"\n  "net/http"\n\n  "github.com/gin-gonic/gin"\n)\n\nvar html = template.Must(template.New("https").Parse(`\n<html>\n<head>\n  <title>Https Test</title>\n  <script src="/assets/app.js"></script>\n</head>\n<body>\n  <h1 style="color:red;">Welcome, Ginner!</h1>\n</body>\n</html>\n`))\n\nfunc main() {\n  r := gin.Default()\n  r.Static("/assets", "./assets")\n  r.SetHTMLTemplate(html)\n\n  r.GET("/", func(c *gin.Context) {\n    if pusher := c.Writer.Pusher(); pusher != nil {\n      // use pusher.Push() to do server push\n      if err := pusher.Push("/assets/app.js", nil); err != nil {\n        log.Printf("Failed to push: %v", err)\n      }\n    }\n    c.HTML(http.StatusOK, "https", gin.H{\n      "status": "success",\n    })\n  })\n\n  // Listen and Server in https://127.0.0.1:8080\n  r.RunTLS(":8080", "./testdata/server.pem", "./testdata/server.key")\n}\n```','{"source": "go-gin", "version": "1.12", "language": "go", "title": "Gin Quick Start", "section_title": "doc", "url": "https://github.com/gin-gonic/gin/blob/master/docs/doc.md", "topics": "gin,http,doc", "categories": "web,go,rest"}');
